  function assertDomOrStop() {
    const required = [
      ["app", dom.app],
      ["views", dom.views && dom.views.length],
      ["modeCards", dom.modeCards && dom.modeCards.length],
      ["warmupStartBtn", dom.warmupStartBtn],
      ["warmupChoices", dom.warmupChoices],
      ["warmupPromptText", dom.warmupPromptText],
      ["warmupStructureBox", dom.warmupStructureBox],
      // 旧「構造決定クイズ」(mode="standard") は削除済み。逆合成解析モードが代替。
    ];

    const missing = required.filter(([, v]) => !v).map(([k]) => k);
    if (missing.length) {
      console.error("DOM取得に失敗。HTMLの閉じタグ崩れ/ID重複/読み込み順を確認してください。", {
        missing,
        app: dom.app,
        views: dom.views?.length,
        modeCards: dom.modeCards?.length,
      });
      return false;
    }
    return true;
  }

