  /* =========================================================
    ユーティリティ
  ========================================================= */
  function shuffleArray(array) {
    const a = array.slice();
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }

  function normalizeName(s) {
    return (s ?? "")
      .trim()
      .toLowerCase()
      .replace(/\s+/g, "")
      .replace(/[‐‑–—−]/g, "-");
  }

  function getAcceptedAnswers(mol) {
    const set = new Set();
    set.add(normalizeName(mol.displayName));
    set.add(normalizeName(mol.commonName));
    if (mol.iupacName) set.add(normalizeName(mol.iupacName));
    return set;
  }

  function renderList(ulEl, items) {
    ulEl.innerHTML = "";
    items.forEach((t) => {
      const li = document.createElement("li");
      li.textContent = t;
      ulEl.appendChild(li);
    });
  }

  function ensureStandardSummaryBox() {
    if (!dom.stdAfterArea) return null;
    let box = dom.stdAfterArea.querySelector("#stdResultSummaryBox");
    if (box) return box;

    box = document.createElement("div");
    box.id = "stdResultSummaryBox";
    box.style.margin = "10px 0 14px";
    box.style.padding = "10px 12px";
    box.style.border = "1px solid #ddd";
    box.style.borderRadius = "10px";
    box.style.background = "#fafafa";
    box.innerHTML = `
      <div><strong>Time:</strong> <span id="stdResultTimeText">-</span></div>
      <div><strong>正誤:</strong> <span id="stdResultJudgeText">-</span></div>
      <div><strong>ヒント使用回数:</strong> <span id="stdResultHintsText">0</span> 回</div>
    `;
    dom.stdAfterArea.prepend(box);
    return box;
  }

  function setStandardSummary({ timeSec, isCorrect, hintsUsed }) {
    const box = ensureStandardSummaryBox();
    if (!box) return;
    const t = box.querySelector("#stdResultTimeText");
    const j = box.querySelector("#stdResultJudgeText");
    const h = box.querySelector("#stdResultHintsText");
    if (t) t.textContent = `${timeSec} s`;
    if (j) j.textContent = isCorrect ? "正解" : "不正解";
    if (h) h.textContent = String(hintsUsed);
  }

  /* =========================================================
    ウォームアップ：問題生成
  ========================================================= */
  // ── グローバル設定（localStorage 永続化）─────────────────────────────
  // Phase 1: 構造式の表記スタイル（骨格式 / 縮合構造式）のみ
  const SETTINGS_STORAGE_KEY = "orgQuizSettings_v1";

  function loadSettings() {
    try {
      const raw = localStorage.getItem(SETTINGS_STORAGE_KEY);
      if (!raw) return;
      const obj = JSON.parse(raw);
      if (obj && typeof obj === "object") {
        if (obj.formulaStyle === "skeletal" || obj.formulaStyle === "condensed") {
          state.settings.formulaStyle = obj.formulaStyle;
        }
        if (["light", "dark", "auto"].includes(obj.theme)) {
          state.settings.theme = obj.theme;
        }
      }
    } catch (_) { /* localStorage 不可・JSON 破損は無視 */ }
  }

  function saveSettings() {
    try {
      localStorage.setItem(SETTINGS_STORAGE_KEY, JSON.stringify(state.settings));
    } catch (_) { /* 保存失敗は無視 */ }
  }

  // ── ダークモード適用 ────────────────────────────────────────────
  // theme: "light" | "dark" | "auto"
  // <html data-theme="dark|light"> をセット → CSS 側 [data-theme="dark"] が反応
  function applyTheme() {
    const root = document.documentElement;
    let resolved = state.settings.theme;
    if (resolved === "auto") {
      const mq = window.matchMedia && window.matchMedia("(prefers-color-scheme: dark)");
      resolved = (mq && mq.matches) ? "dark" : "light";
    }
    root.setAttribute("data-theme", resolved);
  }

  // OS のテーマ変更を監視（auto 時のみ追従）
  function bindAutoThemeListener() {
    if (!window.matchMedia) return;
    const mq = window.matchMedia("(prefers-color-scheme: dark)");
    const handler = () => {
      if (state.settings.theme === "auto") applyTheme();
    };
    if (mq.addEventListener) mq.addEventListener("change", handler);
    else if (mq.addListener) mq.addListener(handler);  // legacy
  }

  function bindGlobalSettingsEvents() {
    // テーマラジオ
    const themeRadios = document.querySelectorAll('#themeRadios input[name="theme"]');
    themeRadios.forEach((r) => {
      r.checked = (r.value === state.settings.theme);
      r.addEventListener("change", () => {
        if (r.checked && ["light", "dark", "auto"].includes(r.value)) {
          state.settings.theme = r.value;
          saveSettings();
          applyTheme();
        }
      });
    });

    const radios = document.querySelectorAll('#formulaStyleRadios input[name="formulaStyle"]');
    radios.forEach((r) => {
      // 起動時の選択状態を反映
      r.checked = (r.value === state.settings.formulaStyle);
      r.addEventListener("change", () => {
        if (r.checked && (r.value === "skeletal" || r.value === "condensed")) {
          state.settings.formulaStyle = r.value;
          saveSettings();
          // 各モードで開いている表示を即時再描画
          // (a) 分子図鑑カードグリッド
          if (typeof renderDict === "function" && state.mode === "dict") {
            try { renderDict(); } catch (_) {}
          }
          // (b) 分子図鑑詳細モーダル
          const modal = document.getElementById("dictDetailModal");
          if (modal && !modal.hidden && state._currentDictMolId) {
            showDictDetail(state._currentDictMolId);
          }
          // (c) 実験室モードの現在の出発物質表示と反応経路チェーン
          if (state.mode === "laboratory") {
            try { if (typeof labRenderCurrentMol === "function") labRenderCurrentMol(); } catch (_) {}
            try { if (typeof labRenderChain === "function") labRenderChain(); } catch (_) {}
          }
          // (d) 合成過程モードの連鎖表示
          if (state.mode === "story" && typeof renderStoryChain === "function") {
            try { renderStoryChain(); } catch (_) {}
          }
        }
      });
    });
  }

  // ── ウォームアップ設定パネル（出題範囲チェックボックス）──────────────
  // 教科書に出てくる順（有機化学の典型的な教科書配列）
  function warmupBuildCategoryChecks() {
    if (!dom.warmupCatChecks) return;
    // 分子図鑑モードと同じ 12 ラベルを出題範囲として使う（DICT_LABELS）
    const sorted = DICT_LABELS;
    dom.warmupCatChecks.innerHTML = "";
    for (const cat of sorted) {
      const label = document.createElement("label");
      const cb = document.createElement("input");
      cb.type = "checkbox";
      cb.checked = true;
      cb.value = cat;
      cb.addEventListener("change", () => warmupUpdateEnabledCategories());
      label.appendChild(cb);
      label.appendChild(document.createTextNode(cat));
      dom.warmupCatChecks.appendChild(label);
    }
    // 初期状態: 全ラベル有効
    state.warmup.enabledCategories = new Set(sorted);
  }

  function warmupUpdateEnabledCategories() {
    if (!dom.warmupCatChecks) return;
    const cbs = dom.warmupCatChecks.querySelectorAll('input[type="checkbox"]');
    state.warmup.enabledCategories = new Set();
    cbs.forEach(cb => { if (cb.checked) state.warmup.enabledCategories.add(cb.value); });
  }

  function warmupSetAllCategories(checked) {
    if (!dom.warmupCatChecks) return;
    dom.warmupCatChecks.querySelectorAll('input[type="checkbox"]').forEach(cb => cb.checked = checked);
    warmupUpdateEnabledCategories();
  }

  // ── ウォームアップ問題生成 ──────────────────────────────────────────────

  /**
   * 分子式から炭素数を抽出する（Unicode 添字対応）。
   * 例: "C₂H₆O" → 2、"CH₄" → 1、"Cl化合物" → 0（C は要素として読まない）
   */
  function carbonCount(mol) {
    const f = mol.formula || "";
    const ascii = f.replace(/[₀-₉]/g, (ch) => String(ch.charCodeAt(0) - 0x2080));
    // Cl ではない C（直後が小文字でない C）にマッチ
    const m = ascii.match(/(?<![A-Za-z])C(\d*)(?![a-rt-z])/);
    if (!m) return 0;
    return m[1] ? parseInt(m[1], 10) : 1;
  }

  /**
   * 2 つの文字列の類似度（最長共通部分文字列ベース）。0〜1 の値。
   * 名称の混同（例：フェノール／フェニル／フェノラート）検出に使用。
   */
  function nameSimilarity(s1, s2) {
    if (!s1 || !s2) return 0;
    const a = s1.toLowerCase();
    const b = s2.toLowerCase();
    let maxLen = 0;
    for (let i = 0; i < a.length; i++) {
      for (let j = 0; j < b.length; j++) {
        let k = 0;
        while (i + k < a.length && j + k < b.length && a[i + k] === b[j + k]) k++;
        if (k > maxLen) maxLen = k;
      }
    }
    return maxLen / Math.max(a.length, b.length);
  }

  /**
   * 「混同しやすさ」スコア。target と candidate の類似性を多軸で評価。
   *   - 同分子式（異性体）: +100
   *   - カテゴリ共有数 × 30
   *   - 炭素数差 0/1/2 で +20/+12/+5
   *   - 名称類似（最大 +30）
   *   - 官能基共有 × 15
   * @returns {number}  高いほど紛らわしい
   */
  function confusabilityScore(a, b) {
    if (a.id === b.id) return -1;
    let s = 0;
    if (a.formula && a.formula === b.formula) s += 100;

    const labA = (typeof getMoleculeLabels === "function") ? new Set(getMoleculeLabels(a)) : new Set();
    const labB = (typeof getMoleculeLabels === "function") ? new Set(getMoleculeLabels(b)) : new Set();
    const labShared = [...labA].filter((x) => labB.has(x)).length;
    s += labShared * 30;

    const cA = carbonCount(a), cB = carbonCount(b);
    if (cA > 0 && cB > 0) {
      const d = Math.abs(cA - cB);
      if (d === 0) s += 20;
      else if (d === 1) s += 12;
      else if (d === 2) s += 5;
    }

    s += Math.round(nameSimilarity(a.commonName || "", b.commonName || "") * 30);
    s += Math.round(nameSimilarity(a.displayName || "", b.displayName || "") * 15);

    const fgA = new Set((a.functionalGroups || []).map((x) => x.toLowerCase()));
    const fgB = new Set((b.functionalGroups || []).map((x) => x.toLowerCase()));
    const fgShared = [...fgA].filter((x) => fgB.has(x)).length;
    s += fgShared * 15;

    return s;
  }

  /**
   * 「混同しやすい類似分子」上位 2 + ランダム 1 をディストラクタとして選ぶ。
   *
   * @param {Object} target  正答分子
   * @param {Object[]} allMols  候補プール（フィルタ済み）
   * @param {Object} [opts]
   * @param {(m:Object)=>boolean} [opts.exclude]  追加除外フィルタ（例：同分子式を除く）
   * @param {number} [opts.count=3]
   * @returns {Object[]}  count 個のディストラクタ分子
   */
  function pickConfusableDistractors(target, allMols, opts = {}) {
    const count = opts.count ?? 3;
    const exclude = opts.exclude || (() => false);
    const pool = allMols.filter((m) => m.id !== target.id && !exclude(m));
    if (pool.length === 0) return [];

    // スコア付け
    const scored = pool
      .map((m) => ({ mol: m, score: confusabilityScore(target, m) }))
      .filter((x) => x.score > 0)
      .sort((a, b) => b.score - a.score);

    // 上位 N=8 から 2 つランダム選択（同点付近のばらつきを保つ）
    const topN = scored.slice(0, 8).map((x) => x.mol);
    const top2 = shuffleArray(topN).slice(0, 2);

    // 残りからランダム 1 つ（変化を付ける）
    const usedIds = new Set(top2.map((m) => m.id));
    const remaining = pool.filter((m) => !usedIds.has(m.id));
    const randomOne = remaining.length > 0
      ? remaining[Math.floor(Math.random() * remaining.length)]
      : null;

    const out = [...top2];
    if (randomOne) out.push(randomOne);
    // 不足分はスコア順から補完
    let idx = 2;
    while (out.length < count && idx < topN.length) {
      const c = topN[idx++];
      if (!out.find((m) => m.id === c.id)) out.push(c);
    }
    // それでも足りなければ pool からランダム
    while (out.length < count && pool.length > out.length) {
      const c = pool[Math.floor(Math.random() * pool.length)];
      if (!out.find((m) => m.id === c.id)) out.push(c);
    }
    return out.slice(0, count);
  }

  function generateWarmupQuestion() {
    let molList = Object.values(molecules);
    // 出題範囲フィルタ（分子図鑑の 12 ラベルベース）
    const enabled = state.warmup.enabledCategories;
    if (enabled && enabled.size > 0) {
      const filtered = molList.filter(m =>
        getMoleculeLabels(m).some(l => enabled.has(l))
      );
      if (filtered.length >= 4) molList = filtered;
    }
    const mol = molList[Math.floor(Math.random() * molList.length)];

    const questionTypes = ["name-to-structure", "structure-to-name", "formula-to-name", "formula-to-structure"];
    const type = questionTypes[Math.floor(Math.random() * questionTypes.length)];

    const otherMols = molList.filter((m) => m.id !== mol.id);

    // 質の高いディストラクタを選択：上位 2 つ（紛らわしい類似）+ ランダム 1 つ
    // 問題タイプに応じて除外条件を変える：
    //   - 分子式 → ○ 系では「同分子式の他分子」を除外（問題が解けなくなるため）
    //   - 構造／名前 → 系では制限なし
    const isFormulaQuestion = type === "formula-to-name" || type === "formula-to-structure";
    const distractors = pickConfusableDistractors(mol, otherMols, {
      count: 3,
      exclude: isFormulaQuestion ? (m) => m.formula === mol.formula : null,
    });

    let prompt = "";
    let promptSvg = "";
    let questionLabel = "";
    let choices = [];
    const correctId = mol.id;

    // 設定に応じて骨格式 SVG or 縮合構造式 HTML を返すヘルパー
    const struct = (m, variant) => renderStructureForMolecule(m, { variant });

    if (type === "name-to-structure") {
      questionLabel = "この名前の構造式は？";
      prompt = mol.commonName;
      choices = shuffleArray([mol, ...distractors]).map((m) => ({ id: m.id, svg: struct(m, "mini") }));
    }

    if (type === "structure-to-name") {
      questionLabel = "この構造式の化合物名は？";
      promptSvg = struct(mol, "warmup");
      choices = shuffleArray([mol, ...distractors]).map((m) => ({ id: m.id, text: m.commonName }));
    }

    if (type === "formula-to-name") {
      questionLabel = "この分子式の化合物は？";
      prompt = mol.formula;
      choices = shuffleArray([mol, ...distractors]).map((m) => ({ id: m.id, text: m.commonName }));
    }

    if (type === "formula-to-structure") {
      questionLabel = "この分子式の構造式は？";
      prompt = mol.formula;
      choices = shuffleArray([mol, ...distractors]).map((m) => ({ id: m.id, svg: struct(m, "mini") }));
    }

    return { type, prompt, promptSvg, questionLabel, correctId, choices };
  }

  /* =========================================================
    SMILES → SVG プリレンダリング（RDKit.js 使用）
  ========================================================= */
  // camelCase の mol.id を snake_case に変換して moleculeSMILES のキーと照合する
  // 例: "aceticAcid" → "acetic_acid", "propanol1" → "propanol_1"
  function molIdToSmilesKey(id) {
    return id
      .replace(/([a-z])(\d)/g, "$1_$2")          // 文字 + 数字: propanol1 → propanol_1
      .replace(/([A-Z])/g, (m) => "_" + m.toLowerCase()); // 大文字: aceticAcid → acetic_acid
  }

  // RDKit.js の 2D 自動レイアウトでは正しく描画できない分子のカスタム SVG。
  //
  // 値の形式：
  //   (a) 文字列 ─ 1種類の SVG のみ（カードと詳細モーダル両方で使用）
  //   (b) オブジェクト { haworth, chair } ─ 糖類向け：
  //         haworth ＝ 図鑑カード／詳細モーダルの**デフォルト表示**（教科書標準）
  //         chair   ＝ 詳細モーダルで「椅子型配座」タブを押した時の表示
  //
  // 対象：
  //   (1) 立方体・かご型など 3D 形状本質の分子（例：キュバン）
  //   (2) **糖類**（教科書では Haworth 投影式が標準だが、SMILES から自動生成される
  //       2D は鎖状または平面六角形で Haworth とは異なる見た目になる）。
